import React from 'react';
import { ListGroup } from 'react-bootstrap';
// Importamos Button para el botón de limpiar, pero lo estilizaremos con clases Tailwind/CSS.

const FilterSidebar = ({ categories = [], selectedCategory, setSelectedCategory, handleClearFilters }) => {

  // Añadimos la categoría "Todas" manualmente al inicio
  const allCategories = [{ id: 'all', name: 'Todas' }, ...categories];

  return (
    <>
      {/* Título de la sección (Aseguramos color y peso de fuente) */}
      <h6 className="text-gray-900 font-bold mb-3 mt-0">Categorías</h6>

      {/* Lista de categorías */}
      <ListGroup variant="flush" className="p-0 border-0 rounded-lg overflow-hidden">
        {allCategories.map((category) => {
          const isSelected = category.name === selectedCategory || (category.name === 'Todas' && !selectedCategory);
          
          return (
            // CLASES CRÍTICAS:
            // - list-group-item: Clase base de Bootstrap
            // - py-2 px-4: Padding
            // - rounded-lg: Bordes redondeados sutiles
            // - Fondo Oscuro con Texto Blanco cuando está activo
            <ListGroup.Item 
              key={category.id} 
              action 
              onClick={() => setSelectedCategory(category.name === 'Todas' ? '' : category.name)}
              // Estilo personalizado
              className={`
                list-group-item cursor-pointer py-2 px-4 mb-2 
                border-0 rounded-lg transition-all duration-200 text-sm font-medium
                ${isSelected 
                  ? 'bg-[var(--brand-dark)] text-white shadow-md' // Estilo activo (Dark Tecnotitlán)
                  : 'bg-white text-gray-700 hover:bg-gray-100'   // Estilo inactivo
                }
              `}
              style={{ 
                // Aseguramos que el botón "Todas" se vea como activo al inicio
                backgroundColor: isSelected ? 'var(--brand-dark)' : 'var(--card-bg-color)' 
              }}
            >
              {category.name}
            </ListGroup.Item>
          );
        })}
      </ListGroup>
      
      {/* Botón de Limpiar Filtros */}
      {selectedCategory && (
        <button
          type="button"
          onClick={handleClearFilters}
          className="w-full mt-4 py-2 px-4 text-sm font-bold rounded-lg 
            text-red-600 border border-red-300 hover:bg-red-50 transition-all duration-200
            focus:ring-2 focus:ring-red-500 focus:ring-opacity-50"
          style={{ 
            backgroundColor: 'transparent',
            // Asegura que el borde rojo no sea el primario de Bootstrap
            borderColor: 'var(--text-secondary)'
          }}
        >
          Limpiar Filtros
        </button>
      )}
    </>
  );
};

export default FilterSidebar;
